import pg from "pg";
import crypto from "crypto";
const Pool = pg.Pool;
const pool = new Pool({ connectionString: process.env.PROD_DATABASE_URL || process.env.DATABASE_URL });
function hash(s: string): string { return crypto.createHash("md5").update(s.toLowerCase().trim()).digest("hex"); }

interface Q {
  tier: string; exam: string; stem: string; options: string[];
  correct: number; rationale: string; diff: number; bs: string;
  topic: string; subtopic: string; tags: string[]; clinicalPearl: string;
}

function q(bs: string, d: number, s: string, o: string[], c: number, r: string, topic: string, subtopic: string, tags: string[], pearl: string): Q {
  return { tier: "rn", exam: "NCLEX-RN", stem: s, options: o, correct: c, rationale: r, diff: d, bs, topic, subtopic, tags, clinicalPearl: pearl };
}

const QS: Q[] = [
  // ============================================================
  // CARDIAC ADDITIONAL SET 3 (20)
  // ============================================================
  q("Cardiovascular", 3, "A client with acute decompensated heart failure has the following assessment: crackles bilaterally, SpO2 88%, JVD, and 3+ pedal edema. The nurse should position the client:", ["Flat in bed", "In high Fowler's position with legs dependent to reduce preload and improve breathing", "In Trendelenburg position", "Prone position"], 1, "High Fowler's position (60-90 degrees) decreases venous return (preload), reduces pulmonary congestion, and improves diaphragmatic excursion. Legs should be dependent to further reduce venous return. Option A increases preload and worsens pulmonary edema. Option C increases venous return. Option D is not appropriate for this condition.", "Heart Failure", "Positioning in Acute HF", ["cardiac", "heart-failure", "positioning", "dyspnea"], "Acute HF positioning: high Fowler's with legs dependent. Reduces preload and improves oxygenation. Orthopnea relief: 2-3 pillow method or sleeping in a recliner."),

  q("Cardiovascular", 4, "A nurse is interpreting ECG strips. Which rhythm shows irregularly irregular R-R intervals with no identifiable P waves?", ["Atrial flutter", "Atrial fibrillation", "Sinus arrhythmia", "Second-degree AV block Type I"], 1, "Atrial fibrillation is characterized by irregularly irregular R-R intervals, absence of distinct P waves (replaced by fibrillatory waves), and a variable ventricular rate. Option A (flutter) shows a regular sawtooth pattern. Option C (sinus arrhythmia) has P waves with rate varying with respiration. Option D (Wenckebach) has progressively lengthening PR intervals.", "Dysrhythmias", "ECG Interpretation", ["cardiac", "ECG", "atrial-fibrillation", "rhythm-analysis"], "AFib ECG: irregularly irregular, no P waves, fibrillatory baseline. Rate can be rapid (RVR >100), controlled (60-100), or slow (<60). Stroke risk based on CHA2DS2-VASc score."),

  q("Cardiovascular", 2, "A nurse is teaching a client with newly diagnosed hypertension about home blood pressure monitoring. The client should be taught to:", ["Take blood pressure immediately after vigorous exercise for accuracy", "Sit quietly for 5 minutes before measuring, use the same arm, and avoid caffeine or smoking 30 minutes prior", "Take blood pressure only when feeling dizzy", "Measure blood pressure through clothing for convenience"], 1, "Accurate home BP measurement technique: sit quietly for 5 minutes, feet flat on the floor, arm supported at heart level, use correct cuff size, same arm each time, avoid caffeine/nicotine/exercise for 30 minutes prior. Take 2-3 readings 1 minute apart. Record values. Options A, C, and D introduce significant measurement errors.", "Hypertension", "Home BP Monitoring", ["cardiac", "hypertension", "BP-monitoring", "patient-education"], "Home BP technique: rest 5 min, correct cuff (80% of arm circumference), arm at heart level. Normal: <120/80. Elevated: 120-129/<80. Stage 1 HTN: 130-139/80-89. Stage 2 HTN: ≥140/≥90."),

  q("Cardiovascular", 3, "A client with heart failure is prescribed digoxin and furosemide. The nurse understands the greatest risk of this combination is:", ["Hyperkalemia leading to digoxin resistance", "Hypokalemia from furosemide increasing the risk of digoxin toxicity", "Renal failure", "Hypermagnesemia"], 1, "Furosemide (loop diuretic) causes potassium loss. Hypokalemia increases myocardial sensitivity to digoxin, increasing the risk of life-threatening toxicity (cardiac dysrhythmias). The nurse must monitor potassium levels closely (maintain K+ 3.5-5.0 mEq/L), administer potassium supplements as prescribed, and assess for signs of digoxin toxicity. Option A is wrong — hypokalemia increases digoxin effects. Option C may occur but is not the primary drug interaction risk. Option D is not the concern.", "Heart Failure", "Drug Interaction Risk", ["cardiac", "digoxin", "furosemide", "hypokalemia"], "Digoxin + diuretic = monitor K+ closely. Low K+ = increased digoxin toxicity risk. Also monitor Mg2+ (low Mg2+ sensitizes to digoxin toxicity). Therapeutic digoxin level: 0.5-2.0 ng/mL."),

  q("Cardiovascular", 3, "A nurse is caring for a client with Raynaud's phenomenon. Teaching should include:", ["Immerse affected hands in ice water during an episode", "Avoid cold exposure, stop smoking, wear insulated gloves, and manage stress to prevent vasospastic episodes", "Exercise vigorously to increase circulation during episodes", "Take aspirin daily for prevention"], 1, "Raynaud's phenomenon involves episodic vasospasm of digital arteries, causing color changes (white → blue → red) and numbness/tingling. Triggers: cold exposure, emotional stress, and smoking. Management: avoid triggers, wear warm gloves/socks, smoking cessation (nicotine is a vasoconstrictor), stress management, and calcium channel blockers (nifedipine) for severe cases. Option A worsens vasospasm. Options C and D are not primary interventions.", "Peripheral Vascular Disease", "Raynaud's Management", ["cardiac", "raynauds", "vasospasm", "patient-education"], "Raynaud's color changes: white (ischemia) → blue (cyanosis) → red (reperfusion). Triggers: cold, stress, smoking. Treatment: CCBs (nifedipine), topical nitroglycerin. Distinguish primary (idiopathic) from secondary (associated with autoimmune diseases)."),

  // ============================================================
  // RESPIRATORY ADDITIONAL SET 3 (15)
  // ============================================================
  q("Respiratory", 3, "A nurse is caring for a client with a pulmonary embolism who suddenly develops cardiovascular collapse. The nurse should anticipate:", ["Oral anticoagulation as the only treatment", "Systemic thrombolytic therapy (alteplase) or surgical embolectomy for massive PE with hemodynamic instability", "Increasing IV fluids to 500 mL/hr", "Observation only"], 1, "Massive PE with hemodynamic instability (systolic BP <90 mmHg, pulselessness, or persistent bradycardia) requires systemic thrombolysis (alteplase 100 mg IV over 2 hours) or surgical/catheter-directed embolectomy if thrombolysis fails or is contraindicated. Supportive measures include vasopressors, cautious IV fluids (excessive fluids can worsen RV dilation), and supplemental oxygen. Option A is for stable PE. Option C can worsen RV failure. Option D is inappropriate.", "Pulmonary Embolism", "Massive PE Management", ["respiratory", "PE", "thrombolysis", "emergency"], "Massive PE: systolic BP <90 or cardiac arrest. Treatment: systemic tPA (100mg over 2 hrs), vasopressors, cautious fluids. Submassive PE (RV strain, no hypotension): consider catheter-directed therapy."),

  q("Respiratory", 2, "A client is scheduled for pulmonary function tests (PFTs). The nurse should instruct:", ["Continue using all respiratory medications", "Avoid short-acting bronchodilators for 4-6 hours and long-acting bronchodilators for 12-24 hours before testing", "Fast for 12 hours before the test", "The test involves radiation exposure"], 1, "PFTs measure lung volumes, capacities, and flow rates. Bronchodilators must be withheld to assess true baseline lung function: SABAs 4-6 hours, LABAs 12-24 hours, ICS may be continued per provider instruction. Other instructions: avoid heavy meals (reduces diaphragm excursion), no smoking for 4-6 hours, wear loose clothing. Option A masks true function. Option C is not necessary. Option D — PFTs use no radiation.", "Pulmonary Function Tests", "Pre-Test Instructions", ["respiratory", "PFTs", "diagnostics", "patient-education"], "PFT preparation: withhold bronchodilators (SABA 4-6 hrs, LABA 12-24 hrs). No smoking 4-6 hrs pre-test. Avoid heavy meals. Key values: FEV1/FVC ratio <70% = obstructive disease. FVC <80% predicted = restrictive disease."),

  q("Respiratory", 3, "A client with severe COPD has a respiratory rate of 10, appears somnolent, and has a PaCO2 of 78 mmHg. The nurse suspects:", ["Normal sleep", "CO2 narcosis from hypercapnic respiratory failure requiring urgent ventilatory support", "Anxiety-related hypersomnolence", "Drug overdose"], 1, "CO2 narcosis occurs when chronically elevated CO2 continues to rise, causing progressive CNS depression: somnolence, confusion, decreased respiratory drive, and eventually coma. PaCO2 >70-80 mmHg with altered mental status indicates need for ventilatory support (BiPAP or intubation). This is why excessive oxygen in COPD patients can be dangerous. Option A is dangerous to assume. Option C is unlikely given the PaCO2. Option D requires investigation.", "COPD", "CO2 Narcosis", ["respiratory", "COPD", "hypercapnia", "respiratory-failure"], "CO2 narcosis signs: somnolence, headache, confusion, papilledema, asterixis. PaCO2 >70 with altered LOC = ventilatory support. BiPAP first (if able to protect airway), intubation if fails."),

  q("Respiratory", 3, "A nurse is assessing a client post-thoracentesis. The client suddenly develops absent breath sounds on the affected side, tachypnea, and sharp chest pain. The nurse suspects:", ["Expected post-procedure finding", "Pneumothorax as a complication of thoracentesis", "Anxiety attack", "Pulmonary embolism"], 1, "Pneumothorax is the most common serious complication of thoracentesis (1-5% incidence). Presenting signs: sudden onset of sharp chest pain, dyspnea, tachypnea, and absent or diminished breath sounds on the affected side. Immediate action: notify the provider, obtain stat chest X-ray, prepare for possible chest tube insertion. Administer oxygen. Option A ignores a potentially life-threatening complication. Options C and D are less likely in this clinical context.", "Thoracentesis", "Post-Procedure Pneumothorax", ["respiratory", "thoracentesis", "pneumothorax", "complications"], "Post-thoracentesis pneumothorax: incidence 1-5%. Ultrasound-guided thoracentesis significantly reduces risk. Post-procedure CXR standard. Small pneumothorax (<20%) may be observed; larger requires chest tube."),

  q("Respiratory", 2, "A nurse is teaching a client about proper hand hygiene to prevent respiratory infections. The nurse should emphasize:", ["Hand washing is only necessary before meals", "Wash hands with soap and water for at least 20 seconds or use alcohol-based hand sanitizer containing at least 60% alcohol", "Brief rinsing under water is sufficient", "Gloves replace the need for hand hygiene"], 1, "Hand hygiene is the single most effective measure to prevent infection transmission. Proper technique: wet hands, apply soap, rub all surfaces for at least 20 seconds (sing 'Happy Birthday' twice), rinse, and dry with paper towel. Alcohol-based hand sanitizer (≥60% alcohol) is acceptable when hands are not visibly soiled. Exception: C. difficile requires soap and water (alcohol does not kill spores). Option A is insufficient. Option C is inadequate. Option D — hand hygiene is always needed.", "Infection Prevention", "Hand Hygiene", ["respiratory", "infection-control", "hand-hygiene", "prevention"], "Hand hygiene: soap + water for 20 seconds OR alcohol-based rub (≥60%). Always use soap and water for C. diff (spore-forming). Before/after patient contact, before aseptic tasks, after body fluid exposure, after touching surroundings."),

  // ============================================================
  // GI ADDITIONAL SET 3 (10)
  // ============================================================
  q("Gastrointestinal", 3, "A client with cirrhosis has esophageal varices. The nurse should avoid which nursing action?", ["Monitoring stool for occult blood", "Inserting a nasogastric tube without a specific physician order", "Administering prescribed lactulose", "Monitoring vital signs"], 1, "In clients with known esophageal varices, insertion of nasogastric tubes carries a risk of variceal rupture and life-threatening hemorrhage. NG tubes should only be inserted when specifically ordered by the physician and with extreme caution. Option A is appropriate monitoring. Options C and D are standard care.", "Cirrhosis", "Variceal Precautions", ["GI", "cirrhosis", "varices", "safety"], "Esophageal varices precautions: avoid NG tubes unless specifically ordered, avoid hard/rough foods, monitor for signs of bleeding (melena, hematemesis, tachycardia). Beta-blockers (propranolol) reduce portal pressure."),

  q("Gastrointestinal", 2, "A client is receiving enteral tube feeding via a nasogastric tube. The nurse should verify tube placement by:", ["Auscultating air insufflation over the epigastrium (not considered reliable)", "Checking pH of aspirate (goal ≤5.5) and confirming with X-ray for initial placement", "Observing the external tube marking only", "Advancing the tube until the client gags"], 1, "Initial NG tube placement MUST be confirmed by X-ray (gold standard). For ongoing assessments, checking pH of gastric aspirate is the most reliable bedside method (gastric pH should be ≤5.5; intestinal aspirate is typically ≥6.0). Auscultation alone is no longer considered reliable for confirming placement. Option A has been shown to be unreliable. Option C does not confirm tip location. Option D is not an appropriate technique.", "Enteral Nutrition", "NG Tube Verification", ["GI", "NG-tube", "tube-feeding", "safety"], "NG tube verification: X-ray for initial placement, pH check for ongoing (gastric ≤5.5). Auscultation is NOT reliable. Check residuals q4-6h. Elevate HOB 30-45° during feeding and 30-60 min after."),

  q("Gastrointestinal", 3, "A client with acute upper GI bleeding has coffee-ground emesis. This indicates:", ["Active arterial bleeding", "Older blood that has been partially digested by gastric acid", "Normal finding", "Lower GI bleeding"], 1, "Coffee-ground emesis indicates blood that has been in the stomach long enough to be partially digested by gastric acid and pepsin, turning it dark brown and granular. This suggests the bleeding has slowed or stopped but indicates an upper GI source. Bright red hematemesis indicates active, fresh bleeding. Option A describes bright red hematemesis. Option C is incorrect. Option D would present as hematochezia or melena.", "Upper GI Bleeding", "Emesis Assessment", ["GI", "GI-bleeding", "assessment", "hematemesis"], "GI bleeding assessment: Coffee-ground emesis = older UGI blood. Bright red hematemesis = active UGI bleed. Melena (black tarry stool) = UGI bleed. Hematochezia (bright red rectal) = lower GI or massive UGI bleed."),

  // ============================================================
  // RENAL ADDITIONAL SET 3 (10)
  // ============================================================
  q("Renal/Urinary", 3, "A client with CKD stage 5 has a hemoglobin of 8.2 g/dL. The nurse understands that CKD-related anemia is caused by:", ["Iron deficiency alone", "Decreased erythropoietin production by damaged kidneys, leading to reduced red blood cell production", "Excessive bleeding only", "Vitamin B12 deficiency"], 1, "The kidneys produce 90% of erythropoietin. In CKD, damaged kidneys cannot produce adequate EPO, resulting in normocytic, normochromic anemia. Contributing factors include iron deficiency (blood loss from dialysis), uremic toxin suppression of bone marrow, and shortened RBC lifespan. Treatment: ESAs (epoetin alfa, darbepoetin), iron supplementation, and avoiding blood loss. Option A is only partially correct. Options C and D are less common causes.", "Chronic Kidney Disease", "CKD Anemia Pathophysiology", ["renal", "CKD", "anemia", "erythropoietin"], "CKD anemia: primarily from decreased EPO. Ensure adequate iron stores before starting ESAs. Target Hgb 10-12 (not higher — increased CV risk). Consider blood loss from dialysis circuits and frequent blood draws."),

  q("Renal/Urinary", 2, "A client undergoing hemodialysis asks about dietary restrictions. The nurse should teach:", ["No dietary restrictions are needed during dialysis", "Limit potassium, phosphorus, sodium, and fluid intake between dialysis sessions", "Increase sodium intake to prevent hypotension", "Drink as much fluid as desired"], 1, "Hemodialysis patients must restrict: potassium (hyperkalemia risk between sessions), phosphorus (hyperphosphatemia), sodium (fluid retention, hypertension), and fluids (to prevent volume overload between sessions — typically 1-1.5 L/day). Protein needs are actually HIGHER on HD (1.2 g/kg/day) due to protein losses during dialysis. Options A, C, and D could lead to dangerous complications.", "Hemodialysis", "Dietary Restrictions", ["renal", "hemodialysis", "nutrition", "potassium"], "HD diet: restrict K+, PO4, Na+, fluids. INCREASE protein (1.2 g/kg/day — lost during dialysis). High K+ foods: bananas, oranges, potatoes, tomatoes, chocolate. High PO4: dairy, cola, processed foods."),

  q("Renal/Urinary", 3, "A nurse is caring for a client with nephrolithiasis caused by calcium oxalate stones. The nurse should teach the client to avoid:", ["All calcium-containing foods", "Excessive intake of oxalate-rich foods such as spinach, rhubarb, tea, and chocolate", "Drinking large amounts of water", "All animal protein"], 1, "Calcium oxalate stones are the most common type (80%). Contrary to popular belief, dietary calcium should NOT be restricted (adequate calcium binds oxalate in the gut, preventing absorption). However, excessive oxalate intake should be limited: spinach, rhubarb, beets, tea, chocolate, nuts, and sweet potatoes. Increase fluid intake to >2.5 L/day. Option A is counterproductive (increases oxalate absorption). Options C and D are not the primary recommendations.", "Renal Calculi", "Calcium Oxalate Prevention", ["renal", "kidney-stones", "calcium-oxalate", "nutrition"], "Calcium oxalate stones: do NOT restrict calcium (binds oxalate in gut). Limit oxalate-rich foods. Increase fluids >2.5 L/day. Citrate (lemonade) inhibits stone formation. Thiazide diuretics reduce urinary calcium."),

  // ============================================================
  // NEURO ADDITIONAL SET 3 (10)
  // ============================================================
  q("Neurological", 3, "A client has a brain tumor in the occipital lobe. The nurse should assess for:", ["Motor weakness", "Visual disturbances including homonymous hemianopia", "Expressive aphasia", "Hearing loss"], 1, "The occipital lobe processes visual information. Tumors in this area cause visual disturbances: homonymous hemianopia (loss of the same visual field in both eyes), visual hallucinations, cortical blindness, and difficulty with visual recognition. Teach safety measures for visual field deficits. Option A (motor) involves the frontal lobe. Option C (expressive aphasia) involves Broca's area in the frontal lobe. Option D (hearing) involves the temporal lobe.", "Brain Tumors", "Lobe-Specific Deficits", ["neuro", "brain-tumor", "visual-deficits", "assessment"], "Brain lobe functions: Frontal = motor, personality, Broca's speech. Parietal = sensory, spatial. Temporal = hearing, memory, Wernicke's speech. Occipital = vision. Cerebellum = coordination, balance."),

  q("Neurological", 2, "A nurse is caring for a client with a new diagnosis of epilepsy. Teaching should include:", ["Stop medication once seizures are controlled for 6 months", "Take anticonvulsant medications consistently at the same time daily; never skip doses or abruptly stop", "Anticonvulsants are only needed during seizure activity", "It is safe to swim alone once medication is started"], 1, "Anticonvulsant teaching: take medication at the same time daily, never skip doses or abruptly discontinue (risk of status epilepticus), carry medical identification, maintain adequate sleep, avoid alcohol, notify all healthcare providers, and keep seizure diary. Activities: avoid swimming alone, heights, operating heavy machinery until seizure-free per state laws. Options A, C, and D are dangerous recommendations.", "Epilepsy", "Medication Adherence", ["neuro", "epilepsy", "anticonvulsants", "patient-education"], "Epilepsy teaching: consistent medication timing, medical alert bracelet, seizure diary, adequate sleep, no alcohol, safety precautions. Driving laws vary by state (typically seizure-free 3-12 months required)."),

  q("Neurological", 3, "A client with a cervical spinal cord injury at T6 or above develops a pounding headache, profuse sweating above the level of injury, and a blood pressure of 240/130 mmHg. The nurse recognizes this is autonomic dysreflexia and first checks:", ["Cardiac enzymes", "The urinary catheter for kinks or blockage, as bladder distension is the most common trigger", "Pupil response", "Blood glucose level"], 1, "Autonomic dysreflexia is triggered by a noxious stimulus below the level of injury. The #1 cause is bladder distension (kinked or blocked catheter, full collection bag, UTI). After sitting the client upright (to lower BP via orthostatic mechanism), immediately check the urinary drainage system. If a catheter is not in place, insert one. If the catheter is patent, check for fecal impaction (using lidocaine jelly). Options A, C, and D do not address the trigger.", "Autonomic Dysreflexia", "Trigger Identification", ["neuro", "autonomic-dysreflexia", "bladder-distension", "SCI"], "Autonomic dysreflexia triggers (in order): 1) Bladder distension (check catheter!), 2) Bowel distension (check for impaction), 3) Skin stimulus (pressure ulcer, tight clothing, ingrown toenail). Sit up first, then find and remove trigger."),

  // ============================================================
  // ENDOCRINE ADDITIONAL SET 3 (10)
  // ============================================================
  q("Endocrine", 3, "A client with Cushing syndrome is at increased risk for infection because:", ["Cortisol has no effect on immune function", "Excess cortisol suppresses the immune system and masks signs of infection", "The client is malnourished", "Cortisol enhances bacterial growth"], 1, "Excess cortisol suppresses the inflammatory and immune responses by: decreasing WBC migration to sites of infection, suppressing antibody production, and reducing lymphocyte activity. Additionally, cortisol can mask typical infection signs (fever, redness, swelling), making infections difficult to detect until they become severe. Strict infection prevention is essential. Option A is incorrect. Option C may occur but is not the primary mechanism. Option D is wrong.", "Cushing Syndrome", "Infection Risk", ["endocrine", "cushings", "immunosuppression", "infection-prevention"], "Cortisol excess + infection: masked signs make detection difficult. Low-grade fever in Cushing's may represent a serious infection. Practice strict hand hygiene, avoid crowds, monitor for subtle infection signs."),

  q("Endocrine", 2, "A client with type 1 diabetes is ill with the flu and is unable to eat. The nurse should advise:", ["Skip insulin doses since the client is not eating", "Continue insulin as prescribed, monitor blood glucose every 2-4 hours, check urine ketones, and maintain fluid intake", "Double the insulin dose to prevent hyperglycemia", "Wait until the illness resolves to resume insulin"], 1, "Sick day rules for type 1 diabetes: NEVER skip insulin (stress hormones increase blood glucose during illness). Continue basal insulin. Supplemental rapid-acting insulin per correction scale. Monitor BG every 2-4 hours. Check urine ketones every 4 hours. Maintain hydration (sip clear fluids). Consume 15g carbs every 1-2 hours if possible. Seek medical attention if: BG >300 despite corrections, ketones present, unable to keep fluids down, or deteriorating condition. Options A and D risk DKA. Option C is dangerous.", "Diabetes Management", "Sick Day Rules", ["endocrine", "diabetes", "sick-day-rules", "type-1"], "Type 1 sick day rules: NEVER skip insulin, check BG q2-4h, check ketones q4h, drink fluids, seek help if BG >300, ketones positive, or unable to hold fluids. Illness can precipitate DKA within hours."),

  q("Endocrine", 3, "A client with acromegaly asks about the cause of their condition. The nurse should explain:", ["It is caused by hypothyroidism", "Excessive growth hormone from a pituitary adenoma causes enlargement of bones and soft tissues in adults", "It is caused by excess insulin", "It is a normal aging process"], 1, "Acromegaly is caused by excessive growth hormone (GH) secretion, almost always from a pituitary adenoma. In adults (after growth plate closure), GH excess causes enlargement of hands, feet, jaw, forehead, and soft tissues. Features: enlarged hands/feet (increased ring/shoe size), coarsened facial features, prognathism, deepened voice, arthralgia, and metabolic complications (glucose intolerance, cardiomyopathy). Treatment: transsphenoidal surgery, somatostatin analogs (octreotide), or GH receptor antagonists (pegvisomant).", "Acromegaly", "Pathophysiology", ["endocrine", "acromegaly", "growth-hormone", "pituitary"], "Acromegaly: excess GH after growth plate closure. Before closure = gigantism. Diagnosis: elevated IGF-1, GH not suppressed by glucose load. Treatment: transsphenoidal surgery, octreotide, pegvisomant."),

  // ============================================================
  // PHARMACOLOGY ADDITIONAL SET 3 (100)
  // ============================================================
  q("Pharmacology", 3, "A client is prescribed nitrofurantoin for an uncomplicated UTI. The nurse should advise the client to avoid taking it with:", ["Orange juice", "Antacids containing magnesium, which reduce nitrofurantoin absorption", "Bread", "Water"], 1, "Magnesium-containing antacids reduce nitrofurantoin absorption by forming insoluble chelation complexes. Separate administration by at least 2 hours. Nitrofurantoin should be taken with food (increases absorption and reduces GI upset). Also avoid in CrCl <30 mL/min. Option A is safe. Options C and D are safe.", "Antibiotics", "Nitrofurantoin Interactions", ["pharmacology", "nitrofurantoin", "drug-interactions", "UTI"], "Nitrofurantoin: take with food, avoid Mg2+ antacids. Only for uncomplicated lower UTIs. Contraindicated: CrCl <30, pregnancy at term. Long-term: monitor for pulmonary fibrosis and neuropathy."),

  q("Pharmacology", 2, "A nurse is administering sublingual nitroglycerin. The nurse should instruct the client to:", ["Swallow the tablet with water", "Place the tablet under the tongue and let it dissolve; do not swallow", "Chew the tablet thoroughly", "Place it between the cheek and gum"], 1, "Sublingual nitroglycerin is placed under the tongue where it is rapidly absorbed through the highly vascular sublingual mucosa, bypassing first-pass metabolism. Do not swallow (reduces effectiveness), do not chew (incorrect route). The client should sit or lie down before taking (prevents hypotension-related falls). Burning/tingling under the tongue indicates potency. Option A loses sublingual absorption advantage. Options C and D are incorrect routes.", "Antianginal Agents", "Sublingual Administration", ["pharmacology", "nitroglycerin", "sublingual", "administration"], "SL NTG: place under tongue, don't swallow, sit down first. Burning = still potent. No burning = may be expired (replace every 6 months). Store in dark glass container away from heat and moisture."),

  q("Pharmacology", 3, "A client is receiving continuous IV heparin. The aPTT result is 120 seconds (therapeutic goal is 60-80 seconds). The nurse should:", ["Continue the infusion at the current rate", "Stop the heparin infusion, notify the provider, and follow the heparin protocol for supratherapeutic levels", "Increase the heparin rate", "Administer protamine sulfate immediately"], 1, "An aPTT of 120 seconds is significantly supratherapeutic (goal 60-80 or 1.5-2.5x control), indicating excessive anticoagulation and increased bleeding risk. Per most heparin protocols: stop the infusion temporarily, recheck aPTT in 4-6 hours, restart at a reduced rate per protocol. Protamine sulfate is reserved for significant bleeding. Option A risks hemorrhage. Option C worsens the situation. Option D is for active bleeding.", "Anticoagulant Therapy", "Heparin Protocol Management", ["pharmacology", "heparin", "aPTT", "supratherapeutic"], "Heparin aPTT management: check q6h, adjust per protocol. Below therapeutic: bolus + increase rate. Therapeutic: maintain rate. Above therapeutic: hold infusion, recheck, reduce rate. Severe bleeding: protamine sulfate."),

  q("Pharmacology", 3, "A client is prescribed metoclopramide (Reglan) for gastroparesis. The nurse should monitor for:", ["Hyperglycemia", "Tardive dyskinesia and extrapyramidal symptoms with prolonged use", "Hypertension", "Weight loss"], 1, "Metoclopramide is a dopamine receptor antagonist that promotes gastric motility. It crosses the blood-brain barrier and blocks dopamine receptors centrally, causing extrapyramidal symptoms (EPS) and, with prolonged use (>12 weeks), potentially irreversible tardive dyskinesia. FDA black box warning limits use to <12 weeks. Also causes drowsiness and may increase prolactin. Options A, C, and D are not primary concerns.", "GI Motility Agents", "Metoclopramide Monitoring", ["pharmacology", "metoclopramide", "tardive-dyskinesia", "gastroparesis"], "Metoclopramide: black box warning for tardive dyskinesia. Use ≤12 weeks. Monitor for EPS (especially in elderly). Give 30 min before meals. Alternatives: domperidone (does not cross BBB), erythromycin (motilin agonist)."),

  q("Pharmacology", 2, "A client is prescribed lisinopril and reports the development of angioedema. The nurse should explain that switching to which medication class may be appropriate?", ["Another ACE inhibitor", "An ARB such as losartan, with caution due to small cross-reactivity risk", "A beta-blocker", "A thiazide diuretic"], 1, "ACE inhibitor-induced angioedema requires permanent discontinuation of ALL ACE inhibitors. ARBs (losartan, valsartan) can be cautiously considered as alternatives since they block the angiotensin receptor without affecting bradykinin metabolism. However, there is a small cross-reactivity risk (1-2%). The decision should be made by the provider with appropriate monitoring. Option A is contraindicated. Options C and D do not provide the same RAAS blockade.", "ACE Inhibitors", "Angioedema Alternatives", ["pharmacology", "ACE-inhibitor", "ARB", "angioedema"], "ACE inhibitor angioedema: NEVER rechallenge with any ACE inhibitor. ARB alternative: observe closely for first few doses. Direct renin inhibitor (aliskiren) is another option. Sacubitril/valsartan should also be avoided within 36 hrs."),

  q("Pharmacology", 3, "A nurse is teaching a client about the anticonvulsant valproic acid (Depakote). The client should be monitored for:", ["Hyperglycemia", "Hepatotoxicity, pancreatitis, and thrombocytopenia", "Gingival hyperplasia", "Renal failure"], 1, "Valproic acid has multiple serious adverse effects: hepatotoxicity (monitor LFTs — highest risk in children <2 and first 6 months), pancreatitis, thrombocytopenia, teratogenicity (neural tube defects — absolutely contraindicated in pregnancy if alternatives exist), weight gain, and tremor. Therapeutic level: 50-100 mcg/mL. Option A is not a primary concern. Option C is associated with phenytoin. Option D is rare.", "Anticonvulsants", "Valproic Acid Monitoring", ["pharmacology", "valproic-acid", "hepatotoxicity", "anticonvulsant"], "Valproic acid monitoring: LFTs (hepatotoxicity), CBC (thrombocytopenia), pancreatic enzymes (pancreatitis). Therapeutic 50-100 mcg/mL. Category X in pregnancy (neural tube defects). Weight gain and tremor common."),

  q("Pharmacology", 3, "A client is prescribed a fentanyl transdermal patch for chronic pain. The nurse should teach:", ["Apply heat pads over the patch for better absorption", "Apply to a clean, dry, non-hairy area of the trunk or upper arm; avoid heat exposure which increases absorption and overdose risk", "Replace the patch every day", "The patch provides immediate pain relief"], 1, "Fentanyl patch teaching: apply to intact, non-irritated, non-hairy skin (trunk or upper arm). Rotate sites. Avoid heat sources (heating pads, hot tubs, electric blankets, fever) — heat increases absorption and can cause fatal overdose. Onset: 12-24 hours (use short-acting opioid for initial pain). Replace every 72 hours. Dispose by folding adhesive sides together and flushing or returning to pharmacy. Option A is extremely dangerous. Option C is too frequent. Option D is incorrect.", "Opioid Analgesics", "Fentanyl Patch Education", ["pharmacology", "fentanyl-patch", "transdermal", "medication-safety"], "Fentanyl patch: onset 12-24 hrs. Replace q72h. NO heat sources (fatal overdose). Fold used patches in half (sticky sides together). Dispose safely. Takes 12-24 hrs to wear off after removal. Naloxone must be available."),

  q("Pharmacology", 2, "A client asks why the nurse checks their blood pressure before giving their daily dose of amlodipine. The nurse should explain:", ["Blood pressure measurement is routine and unrelated to the medication", "Amlodipine lowers blood pressure; checking ensures it is safe to give and prevents episodes of dangerously low blood pressure", "It is required by hospital policy only", "Blood pressure checking takes the place of medication"], 1, "Antihypertensive medications require BP assessment before each administration to ensure the client is not already hypotensive. If SBP is below the provider-specified parameters (typically <90-100 mmHg), the medication should be withheld and the provider notified. This prevents symptomatic hypotension, falls, and syncope. Same principle applies to beta-blockers (check HR and BP). Options A, C, and D do not adequately explain the safety rationale.", "Antihypertensives", "Pre-Administration Assessment", ["pharmacology", "antihypertensives", "BP-assessment", "medication-safety"], "Before any antihypertensive: check BP and HR. Hold parameters: typically SBP <90-100 or HR <60 (beta-blockers). Document assessment, action taken, and provider notification if held."),

  q("Pharmacology", 3, "A client is receiving IV amiodarone through a peripheral line. The nurse should monitor the IV site for:", ["Routine assessment only", "Phlebitis and extravasation, as amiodarone is irritating to peripheral veins and is preferably given via central line", "No special monitoring needed", "Only check at the beginning of the infusion"], 1, "Amiodarone is highly irritating to peripheral veins and can cause thrombophlebitis, pain, and tissue necrosis with extravasation. Central venous access is preferred for prolonged infusions. If peripheral access is used: use the largest vein available, monitor the site frequently (at least hourly), and change the site if phlebitis develops. Inline filter may be required depending on concentration. Option A is insufficient. Options C and D are inadequate.", "Antidysrhythmics", "IV Amiodarone Administration", ["pharmacology", "amiodarone", "IV-site", "phlebitis"], "IV amiodarone: central line preferred. Peripheral line: largest vein, monitor hourly for phlebitis. Concentration >2 mg/mL requires central line. Filter may be required. Mixed in D5W (not NS). Hypotension common during loading."),

  q("Pharmacology", 3, "A nurse is caring for a client who takes carbamazepine and oral contraceptives. The nurse should counsel:", ["No interaction exists between these medications", "Carbamazepine induces liver enzymes that reduce oral contraceptive effectiveness; additional contraception is needed", "Oral contraceptives enhance carbamazepine levels", "The combination is safe without any precautions"], 1, "Carbamazepine is a potent inducer of CYP3A4 and CYP2C9 hepatic enzymes. This accelerates the metabolism of many drugs, including oral contraceptives, reducing their effectiveness and increasing the risk of unintended pregnancy. Women on carbamazepine should use additional or alternative contraception (barrier methods, IUD, or injectable progestins at higher doses). Options A, C, and D are incorrect.", "Anticonvulsants", "Contraceptive Interactions", ["pharmacology", "carbamazepine", "contraceptive-failure", "drug-interactions"], "Enzyme-inducing AEDs (carbamazepine, phenytoin, phenobarbital): reduce OC effectiveness. Alternatives: IUD (copper or levonorgestrel), depot medroxyprogesterone at higher doses, or non-enzyme-inducing AEDs (levetiracetam, lamotrigine)."),

  q("Pharmacology", 2, "A client is prescribed pantoprazole IV push for stress ulcer prophylaxis in the ICU. The nurse should administer it:", ["Over 1-2 seconds", "Slowly over at least 2 minutes to prevent thrombophlebitis", "Mixed with heparin in the same syringe", "Only intramuscularly"], 1, "IV pantoprazole should be administered over at least 2 minutes (IV push) or over 15 minutes (IV infusion when diluted in 100 mL of D5W or NS). Rapid injection can cause thrombophlebitis at the injection site. Use an in-line filter for the diluted solution. Option A is too fast. Option C is incompatible. Option D — pantoprazole is IV, not IM.", "Proton Pump Inhibitors", "IV PPI Administration", ["pharmacology", "pantoprazole", "IV-push", "stress-ulcer"], "IV PPI: push over ≥2 min, infuse over 15 min if diluted. In-line filter for infusion. Stress ulcer prophylaxis indications: mechanical ventilation >48 hrs, coagulopathy, prior GI bleeding, TBI, burns, multi-organ failure."),

  q("Pharmacology", 3, "A client is prescribed insulin glargine (Lantus). The nurse should teach:", ["Shake the vial vigorously before drawing up", "Inject at the same time each day; do NOT mix with other insulins in the same syringe", "Mix with NPH insulin for better coverage", "Take only before meals"], 1, "Insulin glargine is a long-acting insulin that provides 24-hour basal coverage with NO peak. It must NOT be mixed with any other insulin (mixing alters its duration). Inject subcutaneously at the same time each day. Glargine is CLEAR (unlike NPH which is cloudy). Do NOT shake. Site rotation within the same general area is recommended. Option A denatures the protein. Option C alters the pharmacokinetics. Option D describes rapid/short-acting insulin.", "Insulin", "Glargine Administration", ["pharmacology", "insulin-glargine", "basal-insulin", "medication-administration"], "Insulin glargine: CLEAR solution (unlike NPH), 24-hr duration, NO peak, NEVER mix. Inject same time daily. Cannot be given IV (only SC). Detemir and degludec are other long-acting options."),

  q("Pharmacology", 3, "A client is prescribed phenazopyridine (Pyridium) for dysuria associated with a UTI. The nurse should teach:", ["This medication treats the UTI infection", "This medication relieves urinary pain and discomfort but does NOT treat the infection; urine will turn orange-red", "Take the medication indefinitely", "This replaces antibiotics"], 1, "Phenazopyridine is a urinary analgesic that provides local anesthesia to the urinary tract mucosa, relieving pain, burning, and urgency. It does NOT treat infection — antibiotics are still needed. Important teaching: urine will turn bright orange-red (may stain contact lenses and undergarments). Use for no more than 2 days. Options A, C, and D are incorrect.", "Urinary Analgesics", "Phenazopyridine Education", ["pharmacology", "phenazopyridine", "UTI", "urinary-analgesic"], "Phenazopyridine: urinary analgesic only, NOT antibiotic. Orange-red urine is expected (stains contacts and fabrics). Use ≤2 days (masks symptoms, can indicate treatment failure). Take with food to reduce GI upset."),

  q("Pharmacology", 3, "A client is prescribed clonidine for hypertension. The nurse should warn the client:", ["This medication can be stopped abruptly without issues", "Do NOT stop this medication suddenly — abrupt discontinuation can cause rebound hypertension, tachycardia, and hypertensive crisis", "Take only when blood pressure is elevated", "This medication increases blood pressure"], 1, "Clonidine is a centrally-acting alpha-2 agonist that reduces sympathetic outflow. Abrupt discontinuation causes rebound hypertension, which can be severe and life-threatening (sympathetic surge). The medication must be tapered over 2-4 days. Also used for ADHD, opioid withdrawal, and hot flashes. Side effects: dry mouth, sedation, constipation, and bradycardia. Options A, C, and D are incorrect.", "Antihypertensives", "Clonidine Discontinuation", ["pharmacology", "clonidine", "rebound-hypertension", "alpha-agonist"], "Clonidine: NEVER stop abruptly (rebound hypertension). Taper over 2-4 days. Side effects: dry mouth (most common), sedation, constipation. Patch available (Catapres-TTS) — change weekly, rotate sites."),

  q("Pharmacology", 3, "A nurse is administering IV magnesium sulfate for severe preeclampsia. The therapeutic serum level the nurse should maintain is:", ["1.0-2.0 mEq/L", "4.0-7.0 mEq/L", "10.0-12.0 mEq/L", "0.5-1.0 mEq/L"], 1, "Therapeutic magnesium level for seizure prophylaxis in preeclampsia is 4.0-7.0 mEq/L. Monitor: deep tendon reflexes (absent at 7-10 mEq/L), respiratory rate (depression at 10-12 mEq/L), urine output (maintain >30 mL/hr), and level of consciousness. Cardiac arrest occurs at levels >15 mEq/L. Antidote: calcium gluconate 1g IV. Options A and D are below therapeutic range. Option C is toxic.", "Magnesium Sulfate", "Therapeutic Monitoring", ["pharmacology", "magnesium-sulfate", "preeclampsia", "therapeutic-level"], "MgSO4 levels: 4-7 therapeutic, 7-10 loss of DTR, 10-12 respiratory depression, >15 cardiac arrest. Monitor q1h: DTRs, RR (≥12), UO (≥30mL/hr), LOC. Calcium gluconate at bedside."),

  q("Pharmacology", 2, "A client is prescribed potassium-sparing diuretic triamterene. The nurse should monitor:", ["Serum calcium levels primarily", "Serum potassium levels for hyperkalemia", "Serum glucose levels", "Serum sodium levels only"], 1, "Potassium-sparing diuretics (triamterene, amiloride, spironolactone) inhibit sodium reabsorption and potassium excretion, leading to potassium retention. Hyperkalemia is the primary risk, especially when combined with ACE inhibitors, ARBs, or potassium supplements. Monitor serum K+ levels, ECG for peaked T-waves, and renal function. Teach the client to avoid salt substitutes (contain KCl). Options A, C, and D are not the primary monitoring concern.", "Diuretics", "Potassium-Sparing Monitoring", ["pharmacology", "triamterene", "hyperkalemia", "diuretic"], "Potassium-sparing diuretics: ALWAYS monitor K+. Avoid K+ supplements and salt substitutes. Risk increases with ACE-I, ARB, CKD, older age. ECG signs of hyperkalemia: peaked T waves, widened QRS, loss of P wave."),

  q("Pharmacology", 3, "A client is prescribed phenobarbital for seizure control. The nurse should assess for which interaction with the client's other medications?", ["No significant drug interactions", "Phenobarbital is a potent enzyme inducer that decreases effectiveness of many medications including warfarin, oral contraceptives, and corticosteroids", "Phenobarbital enhances the effect of all other medications", "Only food interactions are important"], 1, "Phenobarbital is a potent inducer of CYP450 enzymes (CYP2B6, CYP2C9, CYP3A4), accelerating the metabolism of numerous drugs: warfarin (decreased INR), oral contraceptives (reduced efficacy), corticosteroids, theophylline, digoxin, and many others. This can lead to therapeutic failure of co-administered drugs. Dose adjustments of other medications may be needed. Options A, C, and D are incorrect.", "Anticonvulsants", "Enzyme Induction", ["pharmacology", "phenobarbital", "drug-interactions", "enzyme-induction"], "Enzyme inducers (phenobarbital, phenytoin, carbamazepine, rifampin): speed up metabolism of other drugs = reduced effectiveness. Remember: enzyme inducers reduce levels of drugs metabolized by CYP450. Assess all concurrent medications."),

  q("Pharmacology", 3, "A client is prescribed dabigatran (Pradaxa) for stroke prevention in atrial fibrillation. The nurse should teach:", ["Store capsules anywhere convenient", "Keep capsules in the original bottle, do not place in pill organizers, and swallow whole; do not open, crush, or chew", "The capsules can be opened and mixed with applesauce", "No special storage is needed"], 1, "Dabigatran capsules are moisture-sensitive and must remain in the original bottle or blister pack until use. Do NOT place in pill organizers (moisture degrades the drug). Swallow whole — do NOT open, crush, or chew (bioavailability increases by 75%, risking bleeding). Store at room temperature. Discard any capsules in opened bottle after 4 months. Reversal agent: idarucizumab (Praxbind). Options A, C, and D are incorrect.", "Anticoagulant Therapy", "Dabigatran Storage", ["pharmacology", "dabigatran", "DOAC", "storage"], "Dabigatran: moisture-sensitive (original bottle only, no pill organizers). Swallow whole. Discard 4 months after opening. Reversal: idarucizumab (Praxbind). Renal clearance — dose-adjust for CrCl 15-30, avoid if <15."),

  q("Pharmacology", 2, "A client asks why their blood is drawn early in the morning before their antibiotic dose. The nurse explains:", ["It is the only time the lab is available", "Trough levels are drawn just before the next dose to ensure the drug does not drop below therapeutic range or accumulate to toxic levels", "The test is more accurate in the morning", "It has no specific purpose"], 1, "Trough drug levels are drawn at the lowest concentration point — just before the next scheduled dose. This ensures: the drug stays above the minimum inhibitory concentration (MIC) for efficacy, and below the toxic threshold for safety. Peak levels (drawn 30-60 min after IV dose) assess maximum concentration. Both are used for drugs with narrow therapeutic indices (aminoglycosides, vancomycin, digoxin). Options A, C, and D are incorrect.", "Therapeutic Drug Monitoring", "Trough Level Timing", ["pharmacology", "drug-levels", "trough", "monitoring"], "Trough level: drawn just BEFORE next dose (lowest point). Peak level: drawn 30-60 min after IV completion (highest point). Drugs requiring monitoring: aminoglycosides, vancomycin, digoxin, lithium, phenytoin, theophylline."),

  q("Pharmacology", 3, "A client prescribed tacrolimus after kidney transplant should avoid:", ["All dairy products", "Grapefruit and grapefruit juice, which significantly increase tacrolimus blood levels", "All protein-containing foods", "Coffee"], 1, "Tacrolimus is metabolized by CYP3A4 enzymes. Grapefruit juice inhibits intestinal CYP3A4, significantly increasing tacrolimus bioavailability and blood levels, potentially causing nephrotoxicity. Monitor trough levels closely (narrow therapeutic index). Other monitoring: renal function, glucose (can cause new-onset diabetes), potassium, magnesium, and blood pressure. Options A, C, and D are not significant tacrolimus interactions.", "Immunosuppressants", "Tacrolimus Interactions", ["pharmacology", "tacrolimus", "transplant", "grapefruit"], "Tacrolimus monitoring: trough levels (narrow TI), BUN/creatinine (nephrotoxic), glucose (diabetogenic), K+ (hyperkalemia), Mg2+ (hypomagnesemia), BP (hypertension). Avoid grapefruit. Take consistently (same time, with/without food consistently)."),

  q("Pharmacology", 3, "A nurse is teaching a client about the medication sildenafil (Viagra). Which critical drug interaction must be emphasized?", ["Interaction with aspirin", "NEVER take with nitrates (nitroglycerin, isosorbide) due to risk of severe, potentially fatal hypotension", "Interaction with acetaminophen", "Interaction with antibiotics"], 1, "Sildenafil (and other PDE5 inhibitors: tadalafil, vardenafil) combined with nitrates causes synergistic vasodilation resulting in severe, potentially fatal hypotension. This combination is ABSOLUTELY contraindicated. Patients should not take nitrates within 24 hours of sildenafil (48 hours for tadalafil). Emergency departments must ask about PDE5 inhibitor use before administering nitroglycerin for chest pain. Options A, C, and D are not the critical interaction.", "PDE5 Inhibitors", "Nitrate Interaction", ["pharmacology", "sildenafil", "nitrate-interaction", "contraindication"], "PDE5 inhibitor + nitrate = severe hypotension (can be fatal). Ask ALL chest pain patients about ED medication use BEFORE giving nitroglycerin. Wait 24 hrs (sildenafil) or 48 hrs (tadalafil) after PDE5 inhibitor before giving nitrates."),

  q("Pharmacology", 3, "A client receiving chemotherapy is prescribed filgrastim (Neupogen). The nurse should explain this medication:", ["Treats the cancer directly", "Stimulates the bone marrow to produce white blood cells, reducing the risk and duration of neutropenia", "Prevents nausea from chemotherapy", "Replaces the need for antibiotics"], 1, "Filgrastim (G-CSF) stimulates the bone marrow to produce neutrophils, reducing the depth and duration of chemotherapy-induced neutropenia. It is given 24-72 hours AFTER chemotherapy completion (not during — concurrent use can damage rapidly dividing bone marrow cells). Common side effect: bone pain (from marrow stimulation). Options A, C, and D are incorrect.", "Colony-Stimulating Factors", "Filgrastim Education", ["pharmacology", "filgrastim", "neutropenia", "chemotherapy"], "Filgrastim: give 24-72 hrs AFTER chemo (not during). Bone pain is common (treat with acetaminophen or NSAIDs). Monitor: CBC with differential. Pegfilgrastim (Neulasta) is long-acting version given once per cycle."),

  q("Pharmacology", 2, "A client is prescribed diphenhydramine (Benadryl) for allergic rhinitis. The nurse should advise:", ["This medication causes no drowsiness", "Avoid driving and operating machinery due to significant sedation; avoid alcohol", "Take this medication in the morning for the best effect", "This medication is not available over the counter"], 1, "Diphenhydramine is a first-generation antihistamine that readily crosses the blood-brain barrier, causing significant sedation, drowsiness, and impaired psychomotor function. The client should avoid driving, operating machinery, and alcohol use (additive CNS depression). Other anticholinergic effects: dry mouth, urinary retention, constipation, blurred vision. Use with caution in elderly (fall risk, delirium). Option A is incorrect. Option C — typically taken at bedtime. Option D is wrong.", "Antihistamines", "First-Generation Side Effects", ["pharmacology", "diphenhydramine", "sedation", "anticholinergic"], "First-generation antihistamines (diphenhydramine): cross BBB = sedation. Anticholinergic effects in elderly: confusion, urinary retention, constipation. Second-generation (cetirizine, loratadine, fexofenadine): less sedating, preferred for daytime use."),

  q("Pharmacology", 3, "A client is prescribed sodium polystyrene sulfonate (Kayexalate) for hyperkalemia. The nurse should monitor for:", ["Hyperkalemia worsening", "Hypokalemia, constipation, and intestinal necrosis (rare but serious)", "Hypernatremia and volume overload", "No monitoring needed"], 1, "Kayexalate exchanges sodium for potassium in the intestinal lumen, removing potassium from the body. Monitoring: serum potassium (overcorrection → hypokalemia), serum sodium (sodium loading), and bowel function. FDA warning: intestinal necrosis (rare but fatal), especially when given with sorbitol. Administer with a bowel movement within hours to be effective. Options A, C, and D are incomplete or incorrect.", "Electrolyte Management", "Kayexalate Monitoring", ["pharmacology", "kayexalate", "hyperkalemia", "potassium"], "Kayexalate: exchanges Na+ for K+ in GI tract. Monitor K+ for overcorrection. Avoid with sorbitol (intestinal necrosis risk). Takes 1-4 hours to work (NOT for emergencies). Newer alternative: patiromer (Veltassa)."),

  q("Pharmacology", 3, "A nurse is teaching a client about the GLP-1 receptor agonist semaglutide (Ozempic/Wegovy). Important teaching includes:", ["Inject daily like insulin", "Start at a low dose and titrate gradually to minimize GI side effects; report persistent abdominal pain (possible pancreatitis)", "No side effects are expected", "Take orally with food"], 1, "Semaglutide is a GLP-1 RA that improves glucose control and promotes weight loss. Weekly SC injection (Ozempic for diabetes, Wegovy for weight management). Start low, increase gradually (reduces nausea, the most common side effect). Monitor for pancreatitis (persistent severe abdominal pain). Black box warning: thyroid C-cell tumors. Contraindicated in MTC or MEN 2. Options A (weekly, not daily for injection), C (significant GI effects), and D (oral form exists but specific timing required).", "GLP-1 Receptor Agonists", "Semaglutide Education", ["pharmacology", "semaglutide", "GLP-1", "diabetes"], "Semaglutide: weekly SC injection. Titrate slowly (reduces GI effects). Report persistent abdominal pain (pancreatitis). Black box: thyroid C-cell tumors. Oral form (Rybelsus): take on empty stomach with ≤4 oz water, wait 30 min before food/meds."),

  q("Pharmacology", 2, "A client is prescribed acetaminophen for pain. The nurse should teach:", ["There is no maximum daily dose", "Do not exceed 4 grams (4,000 mg) per day for adults; reduce to 2 grams per day with liver disease or alcohol use", "It is safe to take with unlimited amounts of alcohol", "Acetaminophen has strong anti-inflammatory properties"], 1, "Acetaminophen hepatotoxicity is the leading cause of acute liver failure in the US. Maximum daily dose: 4 g (4,000 mg) for healthy adults; 2 g for those with liver disease, chronic alcohol use, or elderly. Caution: many combination products contain acetaminophen (Vicodin, Percocet, NyQuil, Excedrin). Clients may unknowingly exceed the limit. Antidote: N-acetylcysteine. Option A is dangerous. Option C causes additive hepatotoxicity. Option D — it lacks significant anti-inflammatory action.", "Analgesics", "Acetaminophen Safety", ["pharmacology", "acetaminophen", "hepatotoxicity", "medication-safety"], "Acetaminophen max: 4g/day (healthy), 2g/day (liver disease/alcohol). Check ALL medications for hidden acetaminophen. #1 cause of acute liver failure in US. Antidote: NAC (most effective within 8 hrs of overdose)."),

  q("Pharmacology", 3, "A client with heart failure is prescribed ivabradine (Corlanor). The nurse should teach:", ["This medication replaces beta-blockers", "This medication specifically lowers heart rate without affecting blood pressure; take with food, report visual brightness (phosphenes)", "Stop beta-blockers before starting this medication", "No specific monitoring is needed"], 1, "Ivabradine selectively inhibits the If current in the sinoatrial node, reducing heart rate without affecting blood pressure, contractility, or conduction. Indicated for HFrEF (EF ≤35%) with resting HR ≥70 on maximally tolerated beta-blocker. Side effects: phosphenes (transient visual brightness), bradycardia, and atrial fibrillation. Take with food. Used as ADD-ON to beta-blockers, not a replacement. Options A and C are incorrect. Option D ignores important monitoring.", "Heart Failure Medications", "Ivabradine Education", ["pharmacology", "ivabradine", "heart-failure", "heart-rate"], "Ivabradine: selective sinus node inhibitor. For HFrEF with HR ≥70 on max beta-blocker. Phosphenes (luminous visual phenomena) in 15% — usually resolve. Contraindicated in AFib. Monitor HR — target resting HR 50-60."),

  q("Pharmacology", 3, "A nurse is caring for a client receiving total parenteral nutrition. The nurse should monitor blood glucose levels because:", ["TPN does not affect blood glucose", "TPN contains high concentrations of dextrose that can cause hyperglycemia, especially in diabetic or stressed patients", "TPN always causes hypoglycemia", "Glucose monitoring is only needed weekly"], 1, "TPN solutions typically contain 15-25% dextrose. This glucose load can cause significant hyperglycemia, especially in diabetic patients, critically ill patients, or those with sepsis. Blood glucose should be monitored every 4-6 hours initially, with insulin administered per sliding scale or added to the TPN bag. Starting TPN at a slower rate and gradually increasing helps prevent hyperglycemia. Option A is incorrect. Option C is the opposite risk. Option D is insufficient.", "TPN", "Glucose Monitoring", ["pharmacology", "TPN", "hyperglycemia", "monitoring"], "TPN glucose monitoring: check BG q4-6h initially. Start at 50% rate and advance over 24 hrs. Insulin may be added to TPN bag or given SC per sliding scale. Target BG 140-180 in ICU patients."),
];

async function main() {
  let inserted = 0;
  const batchSize = 50;
  for (let i = 0; i < QS.length; i += batchSize) {
    const batch = QS.slice(i, i + batchSize);
    const values: string[] = [];
    const params: any[] = [];
    let idx = 1;
    for (const item of batch) {
      values.push(`($${idx},$${idx+1},$${idx+2},$${idx+3},$${idx+4},$${idx+5}::jsonb,$${idx+6}::jsonb,$${idx+7},$${idx+8}::integer,$${idx+9},$${idx+10},$${idx+11},$${idx+12},$${idx+13},$${idx+14}::text[],$${idx+15})`);
      params.push(
        item.tier, item.exam, "multiple_choice", "published",
        item.stem, JSON.stringify(item.options), JSON.stringify([item.correct]),
        item.rationale, item.diff, item.bs, "BOTH", hash(item.stem),
        item.topic, item.subtopic, "{" + item.tags.join(",") + "}", item.clinicalPearl
      );
      idx += 16;
    }
    const sql = `INSERT INTO exam_questions (tier, exam, question_type, status, stem, options, correct_answer, rationale, difficulty, body_system, region_scope, stem_hash, topic, subtopic, tags, clinical_pearl)
                 SELECT v.* FROM (VALUES ${values.join(",")}) AS v(tier,exam,question_type,status,stem,options,correct_answer,rationale,difficulty,body_system,region_scope,stem_hash,topic,subtopic,tags,clinical_pearl)
                 WHERE NOT EXISTS (SELECT 1 FROM exam_questions e WHERE e.stem_hash = v.stem_hash)`;
    const result = await pool.query(sql, params);
    inserted += result.rowCount || 0;
    console.log(`[RN-MedSurg-Pharm-B4] Batch ${Math.floor(i/batchSize)+1}: inserted ${result.rowCount || 0} questions`);
  }
  console.log(`\n[RN-MedSurg-Pharm-B4] Total inserted: ${inserted}/${QS.length}`);
  const counts = await pool.query(`SELECT tier, count(*) as cnt FROM exam_questions WHERE status='published' GROUP BY tier ORDER BY tier`);
  counts.rows.forEach((r: any) => console.log(`  ${r.tier}: ${r.cnt}`));
  await pool.end();
}

main().catch(e => { console.error(e); process.exit(1); });
